import json, re

with open('chart.html') as f:
    html = f.read()

# Extract the spec JSON from the HTML
match = re.search(r'var spec = ({.*?});', html, re.DOTALL)
spec = json.loads(match.group(1))

# 1. Top-level vconcat with exactly two entries
assert 'vconcat' in spec, 'No vconcat found'
assert len(spec['vconcat']) == 2, f'Expected 2 vconcat entries, got {len(spec[\"vconcat\"])}'
print('✅ vconcat with 2 entries')

# 2. Both vconcat entries reference an area mark
upper = spec['vconcat'][0]
lower = spec['vconcat'][1]

# Check for area mark in upper (could be in a layer)
def has_area_mark(entry):
    if 'mark' in entry:
        m = entry['mark']
        if isinstance(m, dict) and m.get('type') == 'area':
            return True
        if isinstance(m, str) and m == 'area':
            return True
    if 'layer' in entry:
        return any(has_area_mark(l) for l in entry['layer'])
    return False

assert has_area_mark(upper), 'Upper entry has no area mark'
assert has_area_mark(lower), 'Lower entry has no area mark'
print('✅ Both entries have area marks')

# 3. Lower entry declares selection_interval restricted to x
# Check params at any level
def find_params(obj):
    if isinstance(obj, dict):
        if 'params' in obj:
            for p in obj['params']:
                if 'select' in p:
                    sel = p['select']
                    if sel.get('type') == 'interval' and sel.get('encodings') == ['x']:
                        return p['name']
        for v in obj.values():
            result = find_params(v)
            if result:
                return result
    elif isinstance(obj, list):
        for item in obj:
            result = find_params(item)
            if result:
                return result
    return None

brush_name = find_params(spec)
assert brush_name, 'No interval brush with encodings=[\"x\"] found'
print(f'✅ Interval brush found: {brush_name}')

# 4. Upper entry's x encoding scale references the brush parameter
def find_x_domain_param(entry):
    if 'encoding' in entry and 'x' in entry['encoding']:
        x_enc = entry['encoding']['x']
        if 'scale' in x_enc and 'domain' in x_enc['scale']:
            dom = x_enc['scale']['domain']
            if isinstance(dom, dict) and 'param' in dom:
                return dom['param']
    if 'layer' in entry:
        for layer in entry['layer']:
            result = find_x_domain_param(layer)
            if result:
                return result
    return None

x_domain_param = find_x_domain_param(upper)
assert x_domain_param == brush_name, f'X domain param {x_domain_param} != brush name {brush_name}'
print(f'✅ Upper x-scale domain references brush param: {x_domain_param}')

# 5. Upper entry contains a rule mark with filter + aggregate/window for max price
def find_rule_with_transforms(entry):
    rules = []
    if 'layer' in entry:
        for layer in entry['layer']:
            rules.extend(find_rule_with_transforms(layer))
    if isinstance(entry, dict):
        mark = entry.get('mark', {})
        mark_type = mark.get('type', mark) if isinstance(mark, dict) else mark
        if mark_type == 'rule':
            transforms = entry.get('transform', [])
            has_filter = any('filter' in t and 'param' in t['filter'] for t in transforms)
            has_agg = any('aggregate' in t for t in transforms)
            has_window = any('window' in t for t in transforms)
            has_max = False
            for t in transforms:
                if 'aggregate' in t:
                    for agg in t['aggregate']:
                        if agg.get('op') == 'max' and agg.get('field') == 'price':
                            has_max = True
                if 'window' in t:
                    for w in t.get('sort', []):
                        pass  # window max check would go here
            rules.append({
                'has_filter': has_filter,
                'has_aggregate': has_agg,
                'has_window': has_window,
                'has_max_price': has_max
            })
    return rules

rules = find_rule_with_transforms(upper)
assert len(rules) > 0, 'No rule mark found in upper entry'
rule = rules[0]
assert rule['has_filter'], f'Rule has no filter referencing brush param'
assert rule['has_aggregate'] or rule['has_window'], f'Rule has no aggregate/window transform'
assert rule['has_max_price'], f'Rule does not compute max(price)'
print('✅ Upper entry has rule with filter + aggregate(max(price))')

# 6. Data uses URL form
assert 'data' in spec and 'url' in spec['data'], 'Data does not use URL form'
print(f'✅ Data uses URL: {spec[\"data\"][\"url\"][:60]}...')

print()
print('All acceptance criteria satisfied!')
